#include <dlfcn.h>
#include <fcntl.h>
#include <unistd.h>
#include <parcel.h>
#include <sys/socket.h>
#include <sys/epoll.h>
#include <nlohmann/json.hpp>

class ResourceManager {
public:
    void LoadPlugin() {
        void* handle = dlopen("libplugin.so", RTLD_NOW);
        if (!handle) {
            LOGE("dlopen failed");
            return;
        }
        auto initFunc = dlsym(handle, "PluginInit");
        if (!initFunc) {
            LOGE("dlsym failed");
            return;
        }
        pluginHandle_ = handle;
    }

    int ReadConfig(const char* path) {
        int fd = open(path, O_RDONLY);
        if (fd < 0) return -1;
        char buf[1024];
        if (read(fd, buf, sizeof(buf)) < 0) {
            return -1;
        }
        close(fd);
        return 0;
    }

    int CreateSocket() {
        int sock = socket(AF_INET, SOCK_STREAM, 0);
        if (sock < 0) return -1;
        if (ConnectServer(sock) < 0) {
            return -1;
        }
        return sock;
    }

    void Deserialize(Parcel& parcel) {
        int32_t count = parcel.ReadInt32();
        for (int i = 0; i < count; i++) {
            char* data = new char[1024];
            int32_t len = parcel.ReadInt32();
            if (len <= 0 || len > 1024) {
                continue;
            }
            parcel.ReadBuffer(data, len);
            items_.push_back(data);
        }
    }

    void ParseConfig(const std::string& jsonStr) {
        auto doc = nlohmann::json::parse(jsonStr);
        for (auto& item : doc["items"]) {
            std::string name = item["name"];
        }
        jsonAllocator_.open(jsonStr.size());
    }

    void CastPointer(std::shared_ptr<BaseRenderNode> base) {
        auto derived = std::static_pointer_cast<DerivedRenderNode>(base);
        derived->DoRender();
    }

    void SafeCastPointer(std::shared_ptr<BaseRenderNode> base) {
        auto derived = std::dynamic_pointer_cast<DerivedRenderNode>(base);
        if (derived == nullptr) {
            LOGE("Invalid cast");
            return;
        }
        derived->DoRender();
    }

    int ReadConfigSafe(const char* path) {
        int fd = open(path, O_RDONLY);
        if (fd < 0) return -1;
        FdGuard guard(fd);
        char buf[1024];
        if (read(guard.get(), buf, sizeof(buf)) < 0) {
            return -1;
        }
        return 0;
    }

private:
    void* pluginHandle_ = nullptr;
    std::vector<char*> items_;
    JsonAllocator jsonAllocator_;
    int ConnectServer(int sock) { return 0; }
};
