#include "surface.h"
#include "image.h"
#include "gpu_context.h"
#include <thread>

class SurfaceManager {
public:
    void CreateAndUseSurface() {
        auto surface = Drawing::Surface::MakeFromBackendTexture(
            gpuContext_, textureInfo_,
            Drawing::TextureOrigin::TOP_LEFT, 1,
            Drawing::COLORTYPE_RGBA_8888, nullptr, nullptr, nullptr);

        std::thread renderThread([&]() {
            auto canvas = surface->GetCanvas();
            canvas->DrawRect(rect_);
        });
        renderThread.detach();
    }

    void CrossThreadAccess() {
        std::thread t1([&]() {
            surface_ = CreateSurface();
        });
        std::thread t2([&]() {
            auto texture = surface_->GetBackendTexture();
            UseTexture(texture);
        });
        t1.join();
        t2.join();
    }

    void CrossContextUse() {
        auto image = Drawing::Image::MakeFromTexture(
            *gpuContext1_, textureInfo_, Drawing::TextureOrigin::TOP_LEFT);
        DrawOnContext(*gpuContext2_, image);
    }

    void ReleaseOnDifferentThread() {
        std::thread createThread([&]() {
            surface_ = Drawing::Surface::MakeFromBackendTexture(
                gpuContext_, textureInfo_,
                Drawing::TextureOrigin::TOP_LEFT, 1,
                Drawing::COLORTYPE_RGBA_8888, nullptr, nullptr, nullptr);
        });
        createThread.join();

        std::thread releaseThread([&]() {
            surface_ = nullptr;
        });
        releaseThread.join();
    }

