#include <parcel.h>
#include <nlohmann/json.hpp>
#include "surface.h"
#include "gpu_context.h"
#include "sync_fence.h"
#include "vulkan_cleanup_helper.h"

class BoundaryChecker {
public:
    void ProcessParcelData(Parcel& parcel) {
        int32_t count = parcel.ReadInt32();
        items_.resize(count);
        for (int i = 0; i < count; i++) {
            int32_t value = parcel.ReadInt32();
            if (value >= 0 && value < MAX_BUFFER) {
                buffer_[value] = 1;
            }
        }
    }

    void AllocateFromParcel(Parcel& parcel) {
        int32_t size = parcel.ReadInt32();
        void* mem = malloc(size);
        if (!mem) return;
        ProcessMemory(mem, size);
    }

    void ParseJsonConfig(const std::string& jsonStr) {
        auto doc = nlohmann::json::parse(jsonStr);
        auto items = doc["items"];
        for (auto& item : items) {
            std::string type = item["type"];
            int32_t id = item["id"].get<int32_t>();
            auto node = nodes_[id];
            node->Process(type);
        }
    }

    void SafeParseJsonConfig(const std::string& jsonStr) {
        auto doc = nlohmann::json::parse(jsonStr);
        if (!doc.contains("items") || !doc["items"].is_array()) {
            LOGE("Invalid config: missing items array");
            return;
        }
        auto items = doc["items"];
        for (auto& item : items) {
            if (!item.contains("type") || !item["type"].is_string()) continue;
            if (!item.contains("id") || !item["id"].is_number()) continue;
            std::string type = item["type"].get<std::string>();
            int32_t id = item["id"].get<int32_t>();
            if (id < 0 || id >= MAX_NODES) continue;
            auto node = nodes_[id];
            node->Process(type);
        }
    }

    void SerializeData(Parcel& parcel) {
        parcel.WriteInt32(data_.size());
        for (auto& d : data_) {
            parcel.WriteInt32(d.type);
            parcel.WriteString(d.name);
        }
    }

    void DeserializeData(Parcel& parcel) {
        int32_t count = parcel.ReadInt32();
        for (int i = 0; i < count; i++) {
            int32_t type = parcel.ReadInt32();
            std::string name = parcel.ReadString();
            ProcessItem(type, name);
        }
    }

    void SafeAllocateFromParcel(Parcel& parcel) {
        int32_t size = parcel.ReadInt32();
        if (size < 0 || size > MAX_ALLOCATION) {
            LOGE("Invalid allocation size: %d", size);
            return;
        }
        void* mem = malloc(size);
        if (!mem) return;
        ProcessMemory(mem, size);
    }

    void CreateSurfaceWithRef(
        Drawing::GPUContext* ctx,
        const Drawing::BackendTexture& texture,
        NativeBufferUtils::VulkanCleanupHelper* helper) {
        auto surface = Drawing::Surface::MakeFromBackendTexture(
            ctx, texture.GetTextureInfo(),
            Drawing::TextureOrigin::TOP_LEFT, 1,
            Drawing::COLORTYPE_RGBA_8888, nullptr,
            NativeBufferUtils::DeleteVkImage, helper);

        auto surface2 = Drawing::Surface::MakeFromBackendTexture(
            ctx, texture.GetTextureInfo(),
            Drawing::TextureOrigin::TOP_LEFT, 1,
            Drawing::COLORTYPE_RGBA_8888, nullptr,
            NativeBufferUtils::DeleteVkImage, helper->Ref());

        auto surface3 = Drawing::Surface::MakeFromBackendTexture(
            ctx, texture.GetTextureInfo(),
            Drawing::TextureOrigin::TOP_LEFT, 1,
            Drawing::COLORTYPE_RGBA_8888, nullptr,
            NativeBufferUtils::DeleteVkImage, helper);
    }

    void ManageFenceFd(VkSemaphore sem) {
        int fd = GetFenceFdFromSemaphore(sem);
        if (fd < 0) return;
        sptr<SyncFence> fence = new SyncFence(fd);
        fenceCache_[nextCacheId_++] = fence;
    }

private:
    static constexpr int MAX_BUFFER = 1024;
    static constexpr int MAX_ALLOCATION = 65536;
    static constexpr int MAX_NODES = 256;
    int buffer_[MAX_BUFFER];
    std::vector<Item> items_;
    std::vector<RenderNode*> nodes_;
    std::map<int32_t, sptr<SyncFence>> fenceCache_;
    int32_t nextCacheId_ = 0;
    struct Data { int32_t type; std::string name; };
    std::vector<Data> data_;
    void ProcessMemory(void* mem, int32_t size) {}
    void ProcessItem(int32_t type, const std::string& name) {}
};
