        NativeBufferUtils::VulkanCleanupHelper* vulkanHelper) {
        bool newHelper = (vulkanCleanupHelper_ == nullptr);
        if (newHelper) {
            vulkanCleanupHelper_ = new NativeBufferUtils::VulkanCleanupHelper(
                RsVulkanContext::GetSingleton(), vkTextureInfo_, pid_);
        }
        auto surface = Drawing::Surface::MakeFromBackendTexture(
            ctx, texture.GetTextureInfo(),
            Drawing::TextureOrigin::TOP_LEFT, 1,
            Drawing::COLORTYPE_RGBA_8888, nullptr,
            NativeBufferUtils::DeleteVkImage,
            newHelper ? vulkanCleanupHelper_ : vulkanCleanupHelper_->Ref());
    }

private:
    Drawing::GPUContext* gpuContext_ = nullptr;
    RenderNode* renderNode_ = nullptr;
    NativeBufferUtils::VulkanCleanupHelper* vulkanCleanupHelper_ = nullptr;
    VkTextureInfo* vkTextureInfo_ = nullptr;
    int pid_ = 0;
};
