#include <parcel.h>
#include <cstdint>

class TypeConversionHandler {
public:
    void ProcessExternalData(int64_t externalValue) {
        int32_t result = static_cast<int32_t>(externalValue);
        buffer_[result] = 1;
    }

    void ReadAndConvert(Parcel& parcel) {
        int64_t largeValue = parcel.ReadInt64();
        uint32_t index = static_cast<uint32_t>(largeValue);
        ProcessByIndex(index);
    }

    void ComputeOffset(int32_t base, int32_t multiplier, int32_t offset) {
        int32_t position = base * multiplier + offset;
        if (position >= 0 && position < MAX_SIZE) {
            buffer_[position] = 1;
        }
    }

    void SafeConvert(int64_t externalValue) {
        if (externalValue < 0 || externalValue > INT32_MAX) {
            LOGE("Value out of range: %lld", externalValue);
            return;
        }
        int32_t result = static_cast<int32_t>(externalValue);
        if (result >= 0 && result < MAX_SIZE) {
            buffer_[result] = 1;
        }
    }

    void SafeCompute(int32_t base, int32_t multiplier, int32_t offset) {
        int64_t position = static_cast<int64_t>(base) * multiplier + offset;
        if (position < 0 || position >= MAX_SIZE) {
            LOGE("Offset out of range");
            return;
        }
        buffer_[static_cast<int32_t>(position)] = 1;
    }

    int32_t GetReturnValue() {
        uint64_t largeVal = ComputeLargeValue();
        return static_cast<int32_t>(largeVal);
    }

private:
    static constexpr int MAX_SIZE = 1024;
    int buffer_[MAX_SIZE];
    void ProcessByIndex(uint32_t index) {}
